class InventoryManager:
    """A class for managing product inventory with operations for adding, removing and listing products."""

    def __init__(self):
        """Initialize an empty inventory."""
        self.inventory = {}

    def add_product(self, product_id, name, quantity):
        """
        Add a product to the inventory or update its quantity if it already exists.

        Args:
            product_id: Unique identifier for the product
            name: Name of the product
            quantity: Quantity to add (must be non-negative)

        Raises:
            ValueError: If quantity is negative
        """
        if quantity < 0:
            raise ValueError("Cannot add a negative quantity")

        if product_id in self.inventory:
            self.inventory[product_id]["quantity"] += quantity
            self.inventory[product_id]["name"] = name  # Update name in case it changed
        else:
            self.inventory[product_id] = {
                "product_id": product_id,
                "name": name,
                "quantity": quantity
            }

    def remove_product(self, product_id, quantity):
        """
        Remove a specific quantity of a product from inventory.

        Args:
            product_id: Unique identifier for the product
            quantity: Quantity to remove (must be non-negative)

        Raises:
            ValueError: If quantity is negative or greater than available quantity
            KeyError: If product_id doesn't exist in inventory
        """
        if quantity < 0:
            raise ValueError("Cannot remove a negative quantity")

        if product_id not in self.inventory:
            raise KeyError(f"Product ID {product_id} not found in inventory")

        if quantity > self.inventory[product_id]["quantity"]:
            raise ValueError("Removal quantity exceeds available quantity")

        self.inventory[product_id]["quantity"] -= quantity

        # Remove product from inventory if quantity becomes zero
        if self.inventory[product_id]["quantity"] == 0:
