import (
  "crypto/md5"
  "encoding/base64"
  "errors"
  "net/url"
  "strings"
  "sync"
)

// URL represents a shortened URL pair
type URL struct {
  OriginalURL string
  ShortURL    string
}

// URLShortener manages URL shortening operations
type URLShortener struct {
  urls  map[string]string
  mutex sync.RWMutex
}

// NewURLShortener creates a new URLShortener instance
func NewURLShortener() *URLShortener {
  return &URLShortener{
    urls: make(map[string]string),
  }
}

// StoreURL generates a short URL and stores the mapping
func (us *URLShortener) StoreURL(originalURL string) (URL, error) {
  // Validate URL
  if _, err := url.ParseRequestURI(originalURL); err != nil {
    return URL{}, errors.New("invalid URL format")
  }

  // Generate short URL
  hash := md5.Sum([]byte(originalURL))
  encoded := base64.URLEncoding.EncodeToString(hash[:])
  shortURL := strings.TrimRight(encoded[:8], "=")

  // Store mapping
  us.mutex.Lock()
  defer us.mutex.Unlock()
  us.urls[shortURL] = originalURL

  return URL{
    OriginalURL: originalURL,
    ShortURL:    shortURL,
  }, nil
}

// RetrieveURL returns the original URL for a given short URL
func (us *URLShortener) RetrieveURL(shortURL string) (string, error) {
  us.mutex.RLock()
  defer us.mutex.RUnlock()

  originalURL, exists := us.urls[shortURL]
  if !exists {
    return "", errors.New("short URL not found")
  }

  return originalURL, nil
}

